function rangeToEpubCfi(range){if(!range)return null;if(range.collapsed){const startCfi=createCfiPathComponent(range.startContainer,range.startOffset);if(!startCfi){console.error("Failed to generate point CFI (node might be detached).");return null}return`epubcfi(!${startCfi})`}const startCfi=createCfiPathComponent(range.startContainer,range.startOffset);const endCfi=createCfiPathComponent(range.endContainer,range.endOffset);if(!startCfi&&!endCfi){console.error("Failed to generate both start and end CFIs (nodes might be detached).");return null}if(!startCfi||!endCfi){const validCfi=startCfi||endCfi;if(!startCfi)console.warn("Start CFI generation failed. Falling back to End Point CFI.");if(!endCfi)console.warn("End CFI generation failed. Falling back to Start Point CFI.");return`epubcfi(!${validCfi})`}return`epubcfi(!${startCfi},${endCfi})`}function createCfiPathComponent(node,offset){if(!node)return null;let cfiSteps=[];let currentElement=node.nodeType===Node.TEXT_NODE?node.parentElement:node;while(currentElement&&currentElement!==document.documentElement){let elementIndex=0;let sibling=currentElement;while((sibling=sibling.previousElementSibling)!=null){elementIndex++}let cfiStep=(elementIndex+1)*2;cfiSteps.unshift(cfiStep);currentElement=currentElement.parentElement}if(currentElement!==document.documentElement){console.warn("Node is detached from the DOM tree. Cannot generate CFI.");return null}let path="/"+cfiSteps.join("/");if(node.nodeType===Node.TEXT_NODE){let precedingElementCount=0;let cumulativeOffset=offset;let prevSibling=node.previousSibling;let accumulatingOffsets=true;while(prevSibling){if(prevSibling.nodeType===Node.ELEMENT_NODE){precedingElementCount++;accumulatingOffsets=false}else if(prevSibling.nodeType===Node.TEXT_NODE){if(accumulatingOffsets){cumulativeOffset+=prevSibling.length}}else{}prevSibling=prevSibling.previousSibling}let step=precedingElementCount*2+1;path+=`/${step}:${cumulativeOffset}`}else{let elementCount=0;for(let i=0;i<offset;i++){if(node.childNodes[i]&&node.childNodes[i].nodeType===Node.ELEMENT_NODE){elementCount++}}const targetNode=node.childNodes[offset];if(targetNode&&targetNode.nodeType===Node.TEXT_NODE){const cfiStep=elementCount*2+1;path+=`/${cfiStep}:0`}else{const cfiStep=(elementCount+1)*2;path+=`/${cfiStep}`}}return path}function epubCfiToRange(cfi){const match=cfi.match(/^epubcfi\(([^!)]*)!([^,]+)(?:,([^),]*))?\)$/);if(!match){console.error("Invalid CFI format provided.");return null}const[,,startCfiPath,endCfiPath]=match;let start=findNodeFromCfi(startCfiPath);let end;if(endCfiPath){end=findNodeFromCfi(endCfiPath)}else{end=start}if(!start&&!end){console.error("Could not resolve either start or end CFI location.");return null}if(start&&!end){console.warn("Could not resolve end CFI location. Collapsing range to start.");end=start}else if(!start&&end){console.warn("Could not resolve start CFI location. Collapsing range to end.");start=end}const range=document.createRange();try{range.setStart(start.node,start.offset);if(range.comparePoint(end.node,end.offset)===-1){console.warn("Start and End CFIs are reversed. Swapping to create valid range.");range.setStart(end.node,end.offset);range.setEnd(start.node,start.offset)}else{range.setEnd(end.node,end.offset)}}catch(e){console.error("Error creating range:",e);return null}return range}function findNodeFromCfi(cfiPathComponent){try{const idAssertionRegex=/\[([^\]]+)\]/;const pathParts=cfiPathComponent.split(":");const steps=pathParts[0].split("/").slice(1);let currentNode=document.documentElement;for(let i=0;i<steps.length-1;i++){const stepString=steps[i];const step=parseInt(stepString,10);if(isNaN(step)||step%2!==0){console.warn(`Invalid element step '${stepString}' at depth ${i}. Stopping traversal.`);return{node:currentNode,offset:0}}const targetIndex=step/2-1;let nextNode=targetIndex<currentNode.children.length?currentNode.children[targetIndex]:null;const idMatch=stepString.match(idAssertionRegex);if(idMatch){const expectedId=idMatch[1];if(!nextNode||nextNode.id!==expectedId){const fallbackNode=document.getElementById(expectedId);if(fallbackNode){nextNode=fallbackNode}}}if(!nextNode){console.warn(`Path out of bounds at step '${stepString}'. returning parent container.`);return{node:currentNode,offset:currentNode.childNodes.length}}currentNode=nextNode}const lastStepString=steps[steps.length-1];const lastStep=parseInt(lastStepString,10);if(isNaN(lastStep)){console.warn("Invalid final step. Returning container.");return{node:currentNode,offset:currentNode.childNodes.length}}if(lastStep%2!==0){let rawOffset=pathParts.length>1?parseInt(pathParts[1],10):0;if(isNaN(rawOffset)||rawOffset<0){rawOffset=0}let elementCount=0;for(const child of currentNode.childNodes){if(child.nodeType===Node.ELEMENT_NODE){elementCount++}else if(child.nodeType===Node.TEXT_NODE){const calculatedStep=elementCount*2+1;if(calculatedStep===lastStep){let scanNode=child;let lastTextNode=child;while(scanNode){if(scanNode.nodeType===Node.ELEMENT_NODE){break}if(scanNode.nodeType===Node.TEXT_NODE){lastTextNode=scanNode;if(rawOffset<=scanNode.length){return{node:scanNode,offset:rawOffset}}rawOffset-=scanNode.length}scanNode=scanNode.nextSibling}return{node:lastTextNode,offset:lastTextNode.length}}}}const targetElementCount=(lastStep-1)/2;let currentElementCount=0;for(let i=0;i<currentNode.childNodes.length;i++){if(currentElementCount===targetElementCount){return{node:currentNode,offset:i}}if(currentNode.childNodes[i].nodeType===Node.ELEMENT_NODE){currentElementCount++}}return{node:currentNode,offset:currentNode.childNodes.length}}else{const targetElementIndex=lastStep/2-1;let currentElementIndex=-1;for(let i=0;i<currentNode.childNodes.length;i++){const child=currentNode.childNodes[i];if(child.nodeType===Node.ELEMENT_NODE){currentElementIndex++;if(currentElementIndex===targetElementIndex){let targetNode=child;const idMatch=lastStepString.match(idAssertionRegex);if(idMatch&&targetNode.id!==idMatch[1]){const fallbackNode=document.getElementById(idMatch[1]);if(fallbackNode){targetNode=fallbackNode}}return{node:targetNode,offset:0}}}}return{node:currentNode,offset:currentNode.childNodes.length}}}catch(e){console.error("Error resolving CFI path:",e);return null}}